package com.cho2hand.marketplace.service.impl.trust; import com.cho2hand.marketplace.entity.trust.*;import com.cho2hand.marketplace.exception.ListingAccessDeniedException;import com.cho2hand.marketplace.repository.trust.SellerFollowRepository;import com.cho2hand.marketplace.service.trust.FollowService;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @Transactional public class FollowServiceImpl implements FollowService{private final SellerFollowRepository repository;private final com.cho2hand.marketplace.repository.trust.SellerReviewRepository reviews;public FollowServiceImpl(SellerFollowRepository r,com.cho2hand.marketplace.repository.trust.SellerReviewRepository v){repository=r;reviews=v;}public void follow(Long f,Long s){if(f.equals(s))throw new ListingAccessDeniedException();repository.save(new SellerFollow(f,s));}public void unfollow(Long f,Long s){repository.deleteById(new SellerFollowId(f,s));}@Transactional(readOnly=true)public com.cho2hand.marketplace.dto.trust.TrustScoreResponse trustScore(Long seller){return new com.cho2hand.marketplace.dto.trust.TrustScoreResponse(reviews.averageForSeller(seller),reviews.countForSeller(seller));}}
